import { navigate } from "gatsby";
import * as React from "react";
import { useEffect } from "react";
import { useTranslation } from "react-i18next";

const Btn_select = ({ onAgeVerified }) => {

  const { t } = useTranslation();

  const handleClick = (option) => {

    // Guardar en localStorage
    localStorage.setItem("edad_Accepted", option === "yes" ? "true" : "false");

    if (option === "yes") {
      alert(t("gracias_confirmar"));
      document.body.style.overflow = "auto"; // Permitir scroll
      localStorage.setItem("visited_cigarBbrevas.com", "true");
      // Notificar al padre para ocultar el logo
      if (onAgeVerified) onAgeVerified();
    } else {
      // goto share Page
      navigate("../sharePage/sharePage");
    }

    document.getElementById("btn-action").style.opacity = "0.5";
  };

  useEffect(() => {
    const btnAction = document.getElementById("btn-action");
    if (btnAction) {
      btnAction.style.opacity = "0.1";
      setTimeout(() => {
        btnAction.style.opacity = "1";
      }, 3500);
    }
  }, []);

  return (
    <div
      id="btn-action"
      className="flex transform   xsm:scale-55 scale-75 hover:bg-gray-600/30 flex-row items-center justify-center gap-6 bg-[#b8c2b922] p-6"
    >
      <button
        key="yes"
        onClick={() => handleClick("yes")}
        className="bg-[#007F0D] hover:bg-green-600 hover:scale-105 border-2 border-[#994743] px-9 py-3.5 text-[1.6em] text-white font-bold rounded-lg cursor-pointer transition shadow-lg uppercase tracking-wider"
      >
        {t("si")}
      </button>
      <button
        key="no"
        onClick={() => handleClick("no")}
        className="bg-[#007F0D] hover:bg-green-600 hover:scale-105 border-2 border-[#994743] px-9 py-3.5 text-[1.6em] text-white font-bold rounded-lg cursor-pointer transition shadow-lg uppercase tracking-wider"
      >
        {t("no_gracias")}
      </button>
    </div>
  );
};

export default Btn_select;
