useLayoutEffect(() => {

  if (typeof window === "undefined") return;
  const section = sectionRef.current;
  const track = trackRef.current;
  if (!section || !track) return;

  // Función que recalcula el ancho en cada uso (maneja imágenes que cargan tarde)
  const getTotalScrollX = () => track.scrollWidth - section.offsetWidth;

  const ctx = gsap.context(() => {

    const totalX = getTotalScrollX();
    if (totalX <= 0) return;

    // Auto-scroll tween: se ejecuta después de 2.9s delay
    // Usa función para recalcular x en cada frame
    const autoDur = Math.max(22, totalX / 75);
    const autoTween = gsap.to(track, {
      delay: 2.9,
      x: () => -getTotalScrollX(),
      duration: autoDur,
      ease: "power1.inOut",
      paused: true,
      onComplete: () => {
        gsap.to(section, {
          delay: 1.0,
          duration: 0.8,
          ease: "power2.inOut",
          onComplete: () => st.kill(),
        });
      },
    });

    // H1 "Cigars Brevas" SUBE — animación de entrada
    const h1Tween = gsap.fromTo(h1Ref.current,
      { top: "-4rem" },
      { top: "-10rem", delay: 2.9, duration: 1.2, ease: "power2.out", paused: true }
    );

    // Letrero (logo + texto) BAJA — animación de entrada
    const letreroTween = gsap.fromTo(letreroRef.current,
      { y: 0 },
      { y: "12rem", delay: 2.9, duration: 1.2, ease: "power2.out", paused: true }
    );

    // ScrollTrigger pin + controla play/pause del auto-tween
    const st = ScrollTrigger.create({
      trigger: section,
      start: "top top",
      end: () => "+=" + Math.max(getTotalScrollX(), window.innerHeight * 2),
      pin: true,
      pinSpacing: true,
      anticipatePin: true,
      invalidateOnRefresh: true,
      onEnter: () => {
        autoTween.play();
        h1Tween.play();
        letreroTween.play();
      },
      onEnterBack: () => autoTween.play(),
      onLeave: () => autoTween.pause(),
      onLeaveBack: () => autoTween.pause(),
    });

    // Refresh after images/fonts load so totalX recalculates correctly
    const onLoad = () => ScrollTrigger.refresh();
    window.addEventListener("load", onLoad);
    window.addEventListener("resize", onLoad);

    return () => {
      autoTween.kill();
      h1Tween.kill();
      letreroTween.kill();
      st.kill();
      window.removeEventListener("load", onLoad);
      window.removeEventListener("resize", onLoad);
    };
  }, sectionRef);

  return () => ctx.revert();
}, []);


