import React, { useRef, useEffect, useState } from 'react';
import { StaticImage } from "gatsby-plugin-image";
import { useTranslation } from "react-i18next";
import mallaFrame from "../../static/welcome/-malla-inf.png";

const Welcome = () => {
    const { t } = useTranslation("translation");
    const sectionRef = useRef(null);
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        let timer;
        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    // Wait 1s before triggering all entrance animations
                    timer = setTimeout(() => {
                        setIsVisible(true);
                    }, 1000);
                } else {
                    // Reverse: instantly hide when section scrolls out of view
                    clearTimeout(timer);
                    setIsVisible(false);
                }
            },
            { threshold: 0.2 }
        );
        if (sectionRef.current) observer.observe(sectionRef.current);
        return () => {
            observer.disconnect();
            clearTimeout(timer);
        };
    }, []);

     const scrollToContacto = () => {

    document.getElementById("contactoRef_vitolar").scrollIntoView({ behavior: "smooth" });

                        };

    const onScrool_To = () => {
    
    document.getElementById("compras").scrollIntoView({ behavior: "smooth" });
    
    };


    const animClass = `${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}`;

    return (
        <section ref={sectionRef} id='welcome-section' className="transform scale-100 md:scale-[0.70] relative w-full min-h-screen py-12 sm:py-16 md:py-20 lg:py-24 px-6 sm:px-12 lg:px-24 overflow-hidden bg-[#3f4e4f]">
            {/* Background Decorative Elements */}
            <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-5">
                <div className="absolute top-10 left-10 w-96 h-96 border-2 border-amber-900 rounded-full"></div>
                <div className="absolute bottom-10 right-10 w-[500px] h-[500px] border-2 border-amber-900 rounded-full"></div>
            </div>

            <div className="max-w-8xl mx-auto flex flex-col items-center">
                {/* Header Section */}
                <header className="text-center mb-10 sm:mb-12 md:mb-16 lg:mb-24">
                    <h2 className="bungee-shade-regular text-[2.9rem] sm:text-[3.9rem] md:text-[5.8rem] lg:text-[7.8rem] mb-6 text-[#9B7F49] drop-shadow-lg flex flex-wrap justify-center">
                        {t("wellcome").split('').map((char, i) => {
                            const center = (t("wellcome").length - 1) / 2;
                            const offset = (i - center) * 30;
                            return (
                                <span
                                    key={i}
                                    className="inline-block transition-all duration-700 ease-out"
                                    style={{
                                        transform: isVisible ? 'translateX(0)' : `translateX(${offset}px)`,
                                        opacity: isVisible ? 1 : 0,
                                        transitionDelay: `${i * 70}ms`,
                                    }}
                                >
                                    {char === ' ' ? '\u00A0' : char}
                                </span>
                            );
                        })}
                    </h2>
                    <div className="w-36 h-1.5 bg-[#9B7F49] mx-auto rounded-full"></div>
                </header>

                {/* Main Content Grid */}
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 sm:gap-10 md:gap-12 lg:gap-16 xl:gap-24 items-center w-full">
                    
                    {/* Left Column: Torpedo Image */}
                    <div className="lg:col-span-4 flex flex-row items-center justify-center relative">
                        <div className="relative transform transition-all duration-700 hover:scale-[1.15] hover:text-2rem">
                            {/* Wooden frame */}
                            <div className="rounded-lg overflow-hidden bg-cover bg-center shadow-2xl"
                                 style={{ backgroundImage: `url(${mallaFrame})` }}>
                                <div className="p-[7px] bg-[#4A2F1A]/65">
                                    <div className="p-3 md:p-4 rounded-lg transform rotate-2 hover:rotate-0 transition-transform duration-500">
                                       <div className="w-full h-auto">
                                            <StaticImage
                                                src="../../assets/images/welcome/foto-7.webp"
                                                alt="img fundadora cigar brevas"
                                                className="object-contain w-full max-w-md rounded"
                                                placeholder="blurred"
                                                onContextMenu={(e) => e.preventDefault()}
                                            />
                                       </div>
                                    </div>
                                </div>
                            </div>
                            <p className={`mt-6 text-center italic font-extrabold uppercase tracking-widest select-none text-[1.45rem] sm:text-[1.6rem] md:text-[1.95rem] lg:text-[2.45rem] text-[#D4AF5A] transition-all duration-700 ease-out hover:duration-500 hover:tracking-[0.15em] ${animClass}`}
                               style={{ transform: 'skewX(-12deg)', transitionDelay: '200ms' }}>
                                {t("fermentacion")}
                            </p>
                        </div>
                    </div>

                    {/* Right Column: Descriptions and Additional Images */}
                    <div className="lg:col-span-8 space-y-8 sm:space-y-10 md:space-y-12 lg:space-y-16">
                        
                        {/* Descriptive Text Section - Wooden Frame */}
                        <article id="article_Hoja" className="text-white shadow-2xl rounded-xl relative transform transition-all duration-500 hover:shadow-amber-800/20 overflow-hidden bg-cover bg-center max-w-full"
                                 style={{ backgroundImage: `url(${mallaFrame})` }}>
                            {/* Frame border width */}
                            <div className="p-[7px] bg-[#4A2F1A]/65 overflow-hidden">
                                {/* Inner content area */}
                                <div className="bg-[#9B7F49] p-6 md:p-10 rounded-lg relative overflow-hidden">
                                    <div className="absolute top-1 left-1 w-10 h-10 bg-[#783689]/80 flex items-center justify-center text-[1.95rem] font-serif rounded-full shadow-lg z-10">“</div>
                                    <p className="text-[1.3rem] sm:text-[1.45rem] md:text-[1.95rem] lg:text-[2.45rem] leading-relaxed font-light italic text-justify select-none break-words">
                                        “{t("cada_hoja")}”
                                    </p>
                                    <div className="absolute bottom-1 right-1 w-10 h-10 bg-[#783689]/80 flex items-center justify-center text-[1.95rem] font-serif rounded-full shadow-lg z-10">”</div>
                                </div>
                            </div>
                        </article>

                        {/* Secondary Images Row */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 sm:gap-8 md:gap-10 lg:gap-12 w-full text-[#9B7F49]">
                            {/* Vitolas */}
                            <div onClick={scrollToContacto} className="flex flex-col items-center cursor-pointer group">
                                {/* Wooden frame */}
                                <div className="rounded-lg overflow-hidden bg-cover bg-center shadow-xl transition-all duration-500 group-hover:scale-105 group-hover:shadow-2xl w-full"
                                     style={{
                                       backgroundImage: `url(${mallaFrame})`,
                                       clipPath: isVisible ? 'inset(0)' : 'inset(50%)',
                                       transition: 'clip-path 1s cubic-bezier(0.34, 1.56, 0.64, 1), transform 0.5s ease-out, box-shadow 0.5s ease-out',
                                       transitionDelay: '400ms',
                                     }}>
                                    <div id = "parrafo_bienvenida" className="p-[7px] bg-[#4A2F1A]/65">
                                        <div className="p-2 md:p-3 rounded-lg">
                                            <StaticImage
                                                src="../../assets/images/welcome/vitolario-puros.png"
                                                alt="Diversas Vitolas de Puros Brevas"
                                                className="object-contain aspect-video w-full h-56 md:h-64"
                                                placeholder="blurred"
                                                onContextMenu={(e) => e.preventDefault()}
                                            />
                                        </div>
                                    </div>
                                </div>
                                <span className={`mt-4 text-[1.3rem] sm:text-[1.45rem] md:text-[1.6rem] lg:text-[1.95rem] font-extrabold uppercase tracking-widest text-[#D4AF5A] transition-all duration-700 ease-out group-hover:duration-500 group-hover:tracking-[0.15em] inline-block ${animClass}`}
                                      style={{ transform: 'skewX(-12deg)', transitionDelay: '400ms' }}>
                                    {t("vitolas")}
                                </span>
                            </div>

                            {/* Moldes */}
                            <div className="flex flex-col items-center cursor-pointer group" onClick={onScrool_To}>
                                {/* Wooden frame */}
                                <div className="rounded-lg overflow-hidden bg-cover bg-center shadow-xl transition-all duration-500 group-hover:scale-105 group-hover:shadow-2xl w-full max-w-full"
                                     style={{
                                       backgroundImage: `url(${mallaFrame})`,
                                       clipPath: isVisible ? 'inset(0)' : 'inset(50%)',
                                       transition: 'clip-path 1s cubic-bezier(0.34, 1.56, 0.64, 1), transform 0.5s ease-out, box-shadow 0.5s ease-out',
                                       transitionDelay: '1200ms',
                                     }}>
                                    <div className="p-[7px] bg-[#4A2F1A]/65 overflow-hidden">
                                        <div className="p-2 md:p-3 rounded-lg overflow-hidden">
                                            <StaticImage
                                                src="../../assets/images/welcome/toBuy.webp"
                                                alt="Moldes artesanales usados en la producción de cigarros"
                                                className="object-cover w-full h-56 md:h-64 rounded"
                                                placeholder="blurred"
                                                onContextMenu={(e) => e.preventDefault()}
                                            />
                                        </div>
                                    </div>
                                </div>
                                <span className={`mt-4 text-[1.3rem] sm:text-[1.45rem] md:text-[1.6rem] lg:text-[1.95rem] font-extrabold uppercase tracking-widest text-[#D4AF5A] transition-all duration-700 ease-out group-hover:duration-500 group-hover:tracking-[0.15em] inline-block ${animClass}`}
                                      style={{ transform: 'skewX(-12deg)', transitionDelay: '1200ms' }}>
                                    {t("compras")}
                                </span>
                            </div>
                        </div>
                    </div>

                </div>
            </div>
        </section>
    );
};

export default Welcome;